// ============================================
// AGREGUJ META ADS — PODZIAŁ PLATFORM
// ============================================

const data  = $input.first().json;
const dates = $('📆 Przygotuj Daty1').first().json;

// ── Helpers ──────────────────────────────────
function safeNum(v)   { return parseInt(v)   || 0; }
function safeFloat(v) { return parseFloat(v) || 0; }

function getAction(actions, type) {
  if (!Array.isArray(actions)) return 0;
  const found = actions.find(a => a.action_type === type);
  return found ? safeFloat(found.value) : 0;
}

// ── Pobierz wiersze ───────────────────────────
const rows = data?.data || [];

// ── Mapy agregacji ────────────────────────────
const platformMap = {};
const deviceMap   = {};
const combMap     = {};  // platform + device łącznie

// ── Liczniki globalne ─────────────────────────
let totalSpend       = 0;
let totalImpressions = 0;
let totalClicks      = 0;
let totalReach       = 0;
let totalPurchases   = 0;
let totalLeads       = 0;

// ── Pętla po wierszach ────────────────────────
for (const row of rows) {
  const platform  = row.publisher_platform || 'unknown';
  const device    = row.device_platform    || 'unknown';
  const combKey   = `${platform} / ${device}`;

  const spend       = safeFloat(row.spend);
  const impressions = safeNum(row.impressions);
  const clicks      = safeNum(row.clicks);
  const reach       = safeNum(row.reach);
  const actions     = row.actions || [];

  const purchases = getAction(actions, 'purchase');
  const leads     = getAction(actions, 'lead');
  const videoViews= getAction(actions, 'video_view');
  const linkClicks= getAction(actions, 'link_click');
  const addToCart = getAction(actions, 'add_to_cart');

  // Globalne
  totalSpend       += spend;
  totalImpressions += impressions;
  totalClicks      += clicks;
  totalReach       += reach;
  totalPurchases   += purchases;
  totalLeads       += leads;

  // ── Agregacja per PLATFORMA ──────────────────
  if (!platformMap[platform]) {
    platformMap[platform] = {
      spend: 0, impressions: 0, clicks: 0,
      reach: 0, purchases: 0, leads: 0,
      videoViews: 0, linkClicks: 0, addToCart: 0
    };
  }
  platformMap[platform].spend       += spend;
  platformMap[platform].impressions += impressions;
  platformMap[platform].clicks      += clicks;
  platformMap[platform].reach       += reach;
  platformMap[platform].purchases   += purchases;
  platformMap[platform].leads       += leads;
  platformMap[platform].videoViews  += videoViews;
  platformMap[platform].linkClicks  += linkClicks;
  platformMap[platform].addToCart   += addToCart;

  // ── Agregacja per URZĄDZENIE ──────────────────
  if (!deviceMap[device]) {
    deviceMap[device] = {
      spend: 0, impressions: 0, clicks: 0,
      reach: 0, purchases: 0, leads: 0
    };
  }
  deviceMap[device].spend       += spend;
  deviceMap[device].impressions += impressions;
  deviceMap[device].clicks      += clicks;
  deviceMap[device].reach       += reach;
  deviceMap[device].purchases   += purchases;
  deviceMap[device].leads       += leads;

  // ── Agregacja PLATFORMA + URZĄDZENIE ──────────
  if (!combMap[combKey]) {
    combMap[combKey] = {
      platform, device,
      spend: 0, impressions: 0, clicks: 0,
      reach: 0, purchases: 0, leads: 0
    };
  }
  combMap[combKey].spend       += spend;
  combMap[combKey].impressions += impressions;
  combMap[combKey].clicks      += clicks;
  combMap[combKey].reach       += reach;
  combMap[combKey].purchases   += purchases;
  combMap[combKey].leads       += leads;
}

// ── Wzbogać platformy o wskaźniki ────────────
const platformStats = {};

for (const [name, d] of Object.entries(platformMap)) {
  const ctr      = d.impressions > 0
    ? ((d.clicks / d.impressions) * 100).toFixed(2) : '0.00';
  const cpm      = d.impressions > 0
    ? ((d.spend / d.impressions) * 1000).toFixed(2)  : '0.00';
  const cpc      = d.clicks > 0
    ? (d.spend / d.clicks).toFixed(2)                : '0.00';
  const cpp      = d.reach > 0
    ? (d.spend / d.reach * 1000).toFixed(2)          : '0.00';
  const convRate = d.clicks > 0
    ? (((d.purchases + d.leads) / d.clicks) * 100).toFixed(2) : '0.00';
  const cpa      = (d.purchases + d.leads) > 0
    ? (d.spend / (d.purchases + d.leads)).toFixed(2) : '0.00';

  // Udział procentowy
  const spendPct = totalSpend > 0
    ? ((d.spend / totalSpend) * 100).toFixed(1)       : '0.0';
  const impPct   = totalImpressions > 0
    ? ((d.impressions / totalImpressions) * 100).toFixed(1) : '0.0';
  const clickPct = totalClicks > 0
    ? ((d.clicks / totalClicks) * 100).toFixed(1)     : '0.0';

  // Emoji platformy
  const icons = {
    facebook:         '🔵',
    instagram:        '🟣',
    audience_network: '🌐',
    messenger:        '💬'
  };

  platformStats[name] = {
    icon:        icons[name] || '📢',
    label:       name.charAt(0).toUpperCase() + name.slice(1).replace('_', ' '),

    // Wyniki
    spend:       d.spend.toFixed(2),
    impressions: d.impressions,
    clicks:      d.clicks,
    reach:       d.reach,
    purchases:   Math.round(d.purchases),
    leads:       Math.round(d.leads),
    videoViews:  Math.round(d.videoViews),
    addToCart:   Math.round(d.addToCart),

    // Wskaźniki
    ctr,
    cpm,
    cpc,
    cpp,
    convRate,
    cpa,

    // Udziały %
    spendPct,
    impPct,
    clickPct
  };
}

// ── Wzbogać urządzenia o wskaźniki ───────────
const deviceStats = {};

for (const [name, d] of Object.entries(deviceMap)) {
  const ctr      = d.impressions > 0
    ? ((d.clicks / d.impressions) * 100).toFixed(2) : '0.00';
  const cpm      = d.impressions > 0
    ? ((d.spend / d.impressions) * 1000).toFixed(2)  : '0.00';
  const cpc      = d.clicks > 0
    ? (d.spend / d.clicks).toFixed(2)                : '0.00';
  const spendPct = totalSpend > 0
    ? ((d.spend / totalSpend) * 100).toFixed(1)      : '0.0';

  const deviceIcons = {
    mobile:  '📱',
    desktop: '🖥️',
    tablet:  '📲'
  };

  deviceStats[name] = {
    icon:        deviceIcons[name] || '💻',
    label:       name.charAt(0).toUpperCase() + name.slice(1),
    spend:       d.spend.toFixed(2),
    impressions: d.impressions,
    clicks:      d.clicks,
    reach:       d.reach,
    purchases:   Math.round(d.purchases),
    leads:       Math.round(d.leads),
    ctr,
    cpm,
    cpc,
    spendPct
  };
}

// ── Wzbogać kombinacje platforma+urządzenie ───
const combinedStats = [];

for (const [key, d] of Object.entries(combMap)) {
  const ctr      = d.impressions > 0
    ? ((d.clicks / d.impressions) * 100).toFixed(2) : '0.00';
  const spendPct = totalSpend > 0
    ? ((d.spend / totalSpend) * 100).toFixed(1)     : '0.0';

  combinedStats.push({
    combination: key,
    platform:    d.platform,
    device:      d.device,
    spend:       d.spend.toFixed(2),
    impressions: d.impressions,
    clicks:      d.clicks,
    reach:       d.reach,
    purchases:   Math.round(d.purchases),
    leads:       Math.round(d.leads),
    ctr,
    spendPct
  });
}

// Sortuj kombinacje wg wydatków
combinedStats.sort((a, b) => parseFloat(b.spend) - parseFloat(a.spend));

// ── Wyznacz najlepszą platformę ───────────────
const bestPlatformByROAS = Object.entries(platformStats)
  .filter(([, d]) => parseInt(d.purchases) > 0)
  .sort((a, b) => {
    const roasA = parseFloat(a[1].spend) > 0
      ? parseInt(a[1].purchases) / parseFloat(a[1].spend) : 0;
    const roasB = parseFloat(b[1].spend) > 0
      ? parseInt(b[1].purchases) / parseFloat(b[1].spend) : 0;
    return roasB - roasA;
  })[0]?.[0] || 'N/A';

const bestPlatformByCTR = Object.entries(platformStats)
  .sort((a, b) => parseFloat(b[1].ctr) - parseFloat(a[1].ctr))[0]?.[0] || 'N/A';

const bestDeviceByConv = Object.entries(deviceStats)
  .sort((a, b) => parseInt(b[1].purchases) - parseInt(a[1].purchases))[0]?.[0] || 'N/A';

console.log(`Meta Platformy: ${Object.keys(platformStats).length} platform | Urządzenia: ${Object.keys(deviceStats).length}`);

return [{
  json: {
    ...dates,

    metaPlatforms: {
      // Globalne sumy
      totalSpend:       totalSpend.toFixed(2),
      totalImpressions,
      totalClicks,
      totalReach,
      totalPurchases:   Math.round(totalPurchases),
      totalLeads:       Math.round(totalLeads),

      // Globalne wskaźniki
      overallCTR: totalImpressions > 0
        ? ((totalClicks / totalImpressions) * 100).toFixed(2) : '0.00',
      overallCPM: totalImpressions > 0
        ? ((totalSpend / totalImpressions) * 1000).toFixed(2)  : '0.00',
      overallCPC: totalClicks > 0
        ? (totalSpend / totalClicks).toFixed(2)                : '0.00',

      // Wyniki per platforma
      platformBreakdown: platformStats,

      // Wyniki per urządzenie
      deviceBreakdown: deviceStats,

      // Kombinacje platforma + urządzenie
      combinedBreakdown: combinedStats,

      // Najlepsze
      bestPlatformByROAS,
      bestPlatformByCTR,
      bestDeviceByConv,

      // Liczba platform
      platformCount: Object.keys(platformStats).length,
      deviceCount:   Object.keys(deviceStats).length
    }
  }
}];

// ============================================
// PRZYGOTUJ DATY DLA POPRZEDNIEGO MIESIĄCA
// ============================================

const now = new Date();

const prevMonthStart = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const prevMonthEnd   = new Date(now.getFullYear(), now.getMonth(), 0);

function formatDate(d) {
  return d.toISOString().split('T')[0];
}
function formatDatePL(d) {
  return d.toLocaleDateString('pl-PL', { year: 'numeric', month: 'long' });
}

const startDate  = formatDate(prevMonthStart);
const endDate    = formatDate(prevMonthEnd);
const startTs    = prevMonthStart.getTime();
const endTs      = prevMonthEnd.getTime();
const monthLabel = formatDatePL(prevMonthStart);
const monthShort = prevMonthStart.toLocaleDateString('pl-PL', { month: '2-digit', year: 'numeric' });

console.log(`Generuję raport za: ${monthLabel} (${startDate} → ${endDate})`);

return [{
  json: {
    startDate,
    endDate,
    startTs,
    endTs,
    monthLabel,
    monthShort,
    reportTitle: `Raport Miesięczny — ${monthLabel}`,
    generatedAt: now.toISOString(),
    generatedAtPL: now.toLocaleDateString('pl-PL', {
      day: '2-digit', month: 'long', year: 'numeric',
      hour: '2-digit', minute: '2-digit'
    }),
    prevPrevStart: formatDate(new Date(now.getFullYear(), now.getMonth() - 2, 1)),
    prevPrevEnd:   formatDate(new Date(now.getFullYear(), now.getMonth() - 1, 0))
  }
}];

// ============================================
// AGREGUJ DANE Z GOOGLE ANALYTICS 4
// ============================================

const rows  = $input.all();
const dates = $('📆 Przygotuj Daty1').first().json;

let totalSessions    = 0;
let totalUsers       = 0;
let totalNewUsers    = 0;
let totalPageViews   = 0;
let totalConversions = 0;
let totalRevenue     = 0;
let bounceRates      = [];
let sessionDurations = [];

const sourceMap = {};
const deviceMap = {};
const dailyData = {};

for (const row of rows) {
  const d           = row.json;
  const sessions    = parseInt(d.sessions    || d.metricValues?.[0]?.value || 0);
  const users       = parseInt(d.totalUsers  || d.metricValues?.[1]?.value || 0);
  const newUsers    = parseInt(d.newUsers    || d.metricValues?.[2]?.value || 0);
  const bounceRate  = parseFloat(d.bounceRate || d.metricValues?.[3]?.value || 0);
  const avgDuration = parseFloat(d.averageSessionDuration || d.metricValues?.[4]?.value || 0);
  const pageViews   = parseInt(d.screenPageViews || d.metricValues?.[5]?.value || 0);
  const conversions = parseInt(d.conversions  || d.metricValues?.[6]?.value || 0);
  const revenue     = parseFloat(d.totalRevenue || d.metricValues?.[7]?.value || 0);

  totalSessions    += sessions;
  totalUsers       += users;
  totalNewUsers    += newUsers;
  totalPageViews   += pageViews;
  totalConversions += conversions;
  totalRevenue     += revenue;
  if (bounceRate  > 0) bounceRates.push(bounceRate);
  if (avgDuration > 0) sessionDurations.push(avgDuration);

  const source    = d.sessionSource || d.dimensionValues?.[1]?.value || 'unknown';
  const medium    = d.sessionMedium || d.dimensionValues?.[2]?.value || 'unknown';
  const sourceKey = `${source} / ${medium}`;
  sourceMap[sourceKey] = (sourceMap[sourceKey] || 0) + sessions;

  const device = d.deviceCategory || d.dimensionValues?.[3]?.value || 'unknown';
  deviceMap[device] = (deviceMap[device] || 0) + sessions;

  const date = d.date || d.dimensionValues?.[0]?.value || 'unknown';
  if (date !== 'unknown') dailyData[date] = (dailyData[date] || 0) + sessions;
}

const avgBounceRate     = bounceRates.length > 0
  ? (bounceRates.reduce((a, b) => a + b, 0) / bounceRates.length).toFixed(2) : 0;
const avgSessionDuration = sessionDurations.length > 0
  ? Math.round(sessionDurations.reduce((a, b) => a + b, 0) / sessionDurations.length) : 0;

const topSources = Object.entries(sourceMap)
  .sort((a, b) => b[1] - a[1]).slice(0, 5)
  .map(([source, sessions]) => ({ source, sessions }));

const durationMin = Math.floor(avgSessionDuration / 60);
const durationSec = avgSessionDuration % 60;

return [{
  json: {
    ...dates,
    ga4: {
      totalSessions,
      totalUsers,
      totalNewUsers,
      returningUsers: totalUsers - totalNewUsers,
      totalPageViews,
      totalConversions,
      totalRevenue: totalRevenue.toFixed(2),
      avgBounceRate: parseFloat(avgBounceRate),
      avgSessionDurationSec: avgSessionDuration,
      avgSessionDurationStr: `${durationMin}m ${durationSec}s`,
      pagesPerSession: totalSessions > 0 ? (totalPageViews / totalSessions).toFixed(2) : 0,
      conversionRate: totalSessions > 0 ? ((totalConversions / totalSessions) * 100).toFixed(2) : 0,
      topSources,
      deviceBreakdown: deviceMap,
      dailySessions: dailyData
    }
  }
}];

// ============================================
// AGREGUJ DANE Z GOOGLE ADS
// ============================================

const rows  = $input.all();
const dates = $('📆 Przygotuj Daty1').first().json;

let totalClicks          = 0;
let totalImpressions     = 0;
let totalCostMicros      = 0;
let totalConversions     = 0;
let totalConversionValue = 0;
const campaigns          = [];

for (const row of rows) {
  const results = row.json?.results || [row.json];
  for (const result of results) {
    const metrics  = result?.metrics  || {};
    const campaign = result?.campaign || {};

    const clicks      = parseInt(metrics.clicks || 0);
    const impressions = parseInt(metrics.impressions || 0);
    const costMicros  = parseInt(metrics.costMicros || metrics.cost_micros || 0);
    const conversions = parseFloat(metrics.conversions || 0);
    const convValue   = parseFloat(metrics.conversionsValue || metrics.conversions_value || 0);

    totalClicks          += clicks;
    totalImpressions     += impressions;
    totalCostMicros      += costMicros;
    totalConversions     += conversions;
    totalConversionValue += convValue;

    if (campaign.name && costMicros > 0) {
      campaigns.push({
        name:        campaign.name,
        status:      campaign.status,
        clicks,
        impressions,
        cost:        (costMicros / 1_000_000).toFixed(2),
        ctr:         impressions > 0 ? ((clicks / impressions) * 100).toFixed(2) : '0.00',
        avgCpc:      clicks > 0 ? ((costMicros / 1_000_000) / clicks).toFixed(2) : '0.00',
        conversions: conversions.toFixed(0)
      });
    }
  }
}

const totalCostPLN = totalCostMicros / 1_000_000;
const avgCTR       = totalImpressions > 0 ? ((totalClicks / totalImpressions) * 100) : 0;
const avgCPC       = totalClicks > 0 ? (totalCostPLN / totalClicks) : 0;
const ROAS         = totalCostPLN > 0 ? (totalConversionValue / totalCostPLN) : 0;
const CPA          = totalConversions > 0 ? (totalCostPLN / totalConversions) : 0;

const topCampaigns = campaigns
  .sort((a, b) => parseFloat(b.cost) - parseFloat(a.cost)).slice(0, 5);

return [{
  json: {
    ...dates,
    googleAds: {
      totalClicks,
      totalImpressions,
      totalCostPLN:         totalCostPLN.toFixed(2),
      totalConversions:     Math.round(totalConversions),
      totalConversionValue: totalConversionValue.toFixed(2),
      avgCTR:               avgCTR.toFixed(2),
      avgCPC:               avgCPC.toFixed(2),
      ROAS:                 ROAS.toFixed(2),
      CPA:                  CPA.toFixed(2),
      activeCampaigns:      campaigns.length,
      topCampaigns
    }
  }
}];

// ============================================
// AGREGUJ DANE Z METRICOOL
// ============================================

const data  = $input.first().json;
const dates = $('📆 Przygotuj Daty1').first().json;

const networks = data?.data?.networks || data?.networks || data || {};

function safeNum(val)   { return parseInt(val)   || 0; }
function safeFloat(val) { return parseFloat(val) || 0; }

const socialData       = {};
let totalReach         = 0;
let totalImpressions   = 0;
let totalEngagements   = 0;
let totalFollowers     = 0;
let totalPosts         = 0;

const networkNames = ['instagram', 'facebook', 'linkedin', 'twitter', 'tiktok'];

for (const net of networkNames) {
  const netData          = networks[net] || {};
  const reach            = safeNum(netData.reach            || netData.totalReach);
  const impressions      = safeNum(netData.impressions      || netData.totalImpressions);
  const engagements      = safeNum(netData.engagements      || netData.totalEngagements || netData.interactions);
  const followers        = safeNum(netData.followers        || netData.totalFollowers);
  const followersGrowth  = safeNum(netData.followersGrowth  || netData.newFollowers);
  const posts            = safeNum(netData.posts            || netData.totalPosts || netData.publications);
  const engRate          = followers > 0 ? ((engagements / followers) * 100) : 0;

  if (reach > 0 || followers > 0) {
    socialData[net] = {
      reach, impressions, engagements, followers, followersGrowth, posts,
      engagementRate: engRate.toFixed(2)
    };
    totalReach       += reach;
    totalImpressions += impressions;
    totalEngagements += engagements;
    totalFollowers   += followers;
    totalPosts       += posts;
  }
}

const avgEngRate = totalFollowers > 0
  ? ((totalEngagements / totalFollowers) * 100).toFixed(2) : '0.00';

const bestPosts = data?.data?.bestPosts || data?.bestPosts || [];

return [{
  json: {
    ...dates,
    metricool: {
      totalReach,
      totalImpressions,
      totalEngagements,
      totalFollowers,
      totalPosts,
      avgEngagementRate: parseFloat(avgEngRate),
      networks: socialData,
      bestPosts: bestPosts.slice(0, 3).map(p => ({
        network:     p.network || 'unknown',
        content:     (p.text || p.content || '').substring(0, 100),
        reach:       safeNum(p.reach),
        engagements: safeNum(p.engagements),
        date:        p.date || p.publishedAt
      }))
    }
  }
}];

// ============================================
// POŁĄCZ WSZYSTKIE DANE W JEDEN OBIEKT
// ============================================

const source = $input.first().json;

// ── Skróty do sekcji ────────────────────────────────────────────
const ga4       = source.ga4              || {};
const googleAds = source.googleAds        || {};
const metricool = source.metricool        || {};
const metaC     = source.metaCampaigns    || {};   // kampanie
const metaP     = source.metaPlatforms    || {};   // platformy
const metaD     = source.metaDemographics || {};   // demografia

// ── Łączne wydatki reklamowe ─────────────────────────────────────
const totalAdSpend =
  (parseFloat(googleAds.totalCostPLN) || 0) +
  (parseFloat(metaC.totalSpend)       || 0);

// ── Łączne konwersje ─────────────────────────────────────────────
const totalConversions =
  (parseInt(ga4.totalConversions)       || 0) +
  (parseInt(googleAds.totalConversions) || 0) +
  (parseInt(metaC.totalConversions)     || 0);

// ── Łączna wartość konwersji ─────────────────────────────────────
const totalConversionValue =
  (parseFloat(googleAds.totalConversionValue) || 0) +
  (parseFloat(metaC.totalPurchaseValue)       || 0);

// ── Blended ROAS ─────────────────────────────────────────────────
const blendedROAS = totalAdSpend > 0
  ? (totalConversionValue / totalAdSpend).toFixed(2)
  : '0.00';

// ── Podział wydatków ─────────────────────────────────────────────
const googleSpendPct = totalAdSpend > 0
  ? (((parseFloat(googleAds.totalCostPLN) || 0) / totalAdSpend) * 100).toFixed(1)
  : '0.0';
const metaSpendPct = totalAdSpend > 0
  ? (((parseFloat(metaC.totalSpend) || 0) / totalAdSpend) * 100).toFixed(1)
  : '0.0';

// ── Top kanał ────────────────────────────────────────────────────
const topChannel = (() => {
  const channels = [
    { name: 'Organic Search', value: parseInt(ga4.totalSessions)       || 0 },
    { name: 'Google Ads',     value: parseInt(googleAds.totalClicks)   || 0 },
    { name: 'Meta Ads',       value: parseInt(metaC.totalClicks)       || 0 },
    { name: 'Social Media',   value: parseInt(metricool.totalReach)    || 0 },
  ];
  return channels.sort((a, b) => b.value - a.value)[0]?.name || 'N/A';
})();

// ============================================
// FINALNY OBIEKT
// ============================================
const reportData = {

  // ── Daty ───────────────────────────────────────────────────────
  startDate:       source.startDate,
  endDate:         source.endDate,
  startTs:         source.startTs,
  endTs:           source.endTs,
  monthLabel:      source.monthLabel,
  monthShort:      source.monthShort,
  reportTitle:     source.reportTitle,
  generatedAt:     source.generatedAt,
  generatedAtPL:   source.generatedAtPL,
  prevPrevStart:   source.prevPrevStart,
  prevPrevEnd:     source.prevPrevEnd,

  // ── GA4 ────────────────────────────────────────────────────────
  ga4: {
    totalSessions:          ga4.totalSessions,
    totalUsers:             ga4.totalUsers,
    totalNewUsers:          ga4.totalNewUsers,
    returningUsers:         ga4.returningUsers,
    totalPageViews:         ga4.totalPageViews,
    totalConversions:       ga4.totalConversions,
    totalRevenue:           ga4.totalRevenue,
    avgBounceRate:          ga4.avgBounceRate,
    avgSessionDurationSec:  ga4.avgSessionDurationSec,
    avgSessionDurationStr:  ga4.avgSessionDurationStr,
    pagesPerSession:        ga4.pagesPerSession,
    conversionRate:         ga4.conversionRate,
    topSources:             ga4.topSources      || [],
    deviceBreakdown:        ga4.deviceBreakdown || {},
    dailySessions:          ga4.dailySessions   || {},
  },

  // ── Google Ads ─────────────────────────────────────────────────
  googleAds: {
    totalClicks:           googleAds.totalClicks,
    totalImpressions:      googleAds.totalImpressions,
