function num(n)  { return parseInt(n  || 0).toLocaleString('pl-PL'); }
function pct(n)  { return parseFloat(n || 0).toFixed(2) + '%'; }
function pln(n)  { return parseFloat(n || 0).toLocaleString('pl-PL', { minimumFractionDigits: 2 }) + ' PLN'; }
function x(n)    { return parseFloat(n || 0).toFixed(2) + 'x'; }

function aiList(arr) {
  if (!Array.isArray(arr) || arr.length === 0) return '<li>Brak danych</li>';
  return arr.map(item => `<li>${item}</li>`).join('');
}

// ── Social networks (Metricool) ──────────────────────
function socialNetworks(networks) {
  if (!networks || Object.keys(networks).length === 0) return '<p>Brak danych</p>';
  return Object.entries(networks).map(([net, data]) => `
    <div class="social-card">
      <div class="social-name">${net.toUpperCase()}</div>
      <div class="social-stat"><span>Zasięg</span><strong>${num(data.reach)}</strong></div>
      <div class="social-stat"><span>Zaangażowanie</span><strong>${num(data.engagements)}</strong></div>
      <div class="social-stat"><span>Eng. Rate</span><strong>${data.engagementRate}%</strong></div>
      <div class="social-stat"><span>Followersi</span><strong>${num(data.followers)}</strong></div>
