  table { width:100%; border-collapse:collapse; font-size:13px; }
  th {
    background:#f1f5f9; padding:10px 12px; text-align:left;
    font-size:11px; font-weight:700; color:#64748b;
    text-transform:uppercase; letter-spacing:.5px;
  }
  td { padding:11px 12px; border-bottom:1px solid #f1f5f9; color:#374151; }
  tr:hover td { background:#f8fafc; }

  .ai-grid { display:grid; grid-template-columns:1fr 1fr; gap:20px; }
  .ai-box {
    background:#f8fafc; border-radius:12px; padding:20px;
    border:1px solid #e2e8f0;
  }
  .ai-box h4 { font-size:13px; font-weight:700; text-transform:uppercase; letter-spacing:.8px; color:#94a3b8; margin-bottom:12px; }
  .ai-box ul { padding-left:18px; }
  .ai-box ul li { font-size:14px; color:#374151; margin-bottom:8px; line-height:1.5; }
  .ai-box.good      { border-left:3px solid #22c55e; }
  .ai-box.bad       { border-left:3px solid #ef4444; }
  .ai-box.info      { border-left:3px solid #3b82f6; }
  .ai-box.warn      { border-left:3px solid #f59e0b; }
  .ai-box.meta-rec  { border-left:3px solid #1877f2; }
  .ai-box.budget    { border-left:3px solid #8b5cf6; }

  .social-grid { display:grid; grid-template-columns:repeat(auto-fit,minmax(195px,1fr)); gap:16px; }
  .social-card { background:#f8fafc; border-radius:12px; padding:16px; border:1px solid #e2e8f0; }
  .social-name { font-size:12px; font-weight:800; color:#1e3a5f; text-transform:uppercase; letter-spacing:1px; margin-bottom:12px; padding-bottom:8px; border-bottom:2px solid #e2e8f0; }
  .social-stat { display:flex; justify-content:space-between; font-size:13px; margin-bottom:6px; }
  .social-stat span { color:#94a3b8; }
  .social-stat strong { color:#1e293b; }

  .summary-box {
    background:linear-gradient(135deg,#1e3a5f,#2d6a9f);
    color:white; border-radius:16px; padding:28px 32px; margin-bottom:24px;
  }
  .summary-box h3 { font-size:16px; font-weight:700; opacity:.8; margin-bottom:12px; text-transform:uppercase; letter-spacing:1px; }
  .summary-box p  { font-size:16px; line-height:1.7; opacity:.95; }

  .alert-box { background:#fef2f2; border:2px solid #ef4444; border-radius:12px; padding:20px 24px; margin-bottom:20px; }
  .alert-box h4 { color:#dc2626; font-size:14px; font-weight:700; margin-bottom:8px; }
  .alert-box p  { color:#7f1d1d; font-size:14px; }

  .badge { display:inline-block; padding:3px 9px; border-radius:20px; font-size:11px; font-weight:700; }
  .badge-green  { background:#dcfce7; color:#16a34a; }
  .badge-yellow { background:#fef9c3; color:#ca8a04; }
  .badge-red    { background:#fee2e2; color:#dc2626; }
  .badge-blue   { background:#dbeafe; color:#1d4ed8; }
  .badge-purple { background:#ede9fe; color:#6d28d9; }

  .budget-bar-wrap { background:#f1f5f9; border-radius:8px; height:24px; overflow:hidden; display:flex; margin:16px 0; }
  .budget-bar-g { background:#2d6a9f; height:100%; display:flex; align-items:center; justify-content:center; color:white; font-size:12px; font-weight:700; }
  .budget-bar-m { background:#1877f2; height:100%; display:flex; align-items:center; justify-content:center; color:white; font-size:12px; font-weight:700; }

  .two-col { display:grid; grid-template-columns:1fr 1fr; gap:24px; }
  .three-col { display:grid; grid-template-columns:1fr 1fr 1fr; gap:20px; }

  .subsection {
    background:#f8fafc; border-radius:12px;
    border:1px solid #e2e8f0; padding:20px; margin-top:20px;
  }

  .table-scroll { overflow-x:auto; }

  .footer { text-align:center; padding:32px; color:#94a3b8; font-size:12px; }
  .footer strong { color:#64748b; }

  @media print {
    body { background:white; }
    .section { box-shadow:none; border:1px solid #e2e8f0; }
  }
</style>
</head>
<body>

<!-- HEADER -->
<div class="header">
  <h1>📊 ${d.reportTitle}</h1>
  <p>Kompleksowy raport wyników marketingowych — GA4 · Google Ads · Meta Ads · Social Media</p>
  <div class="date">Wygenerowano: ${d.generatedAtPL}</div>
</div>

<!-- SCORE BANNER -->
<div class="score-banner">
  <div class="score-num">${ai.scoreEmoji || '📊'} ${ai.score || 'N/A'}<span style="font-size:20px;color:#94a3b8">/10</span></div>
  <div class="score-text">
    <h3>Ocena ogólna miesiąca</h3>
    <p>${ai.ocena_opis || 'Analiza dostępna poniżej'} &nbsp;
      <span class="badge badge-${ai.score >= 8 ? 'green' : ai.score >= 6 ? 'yellow' : 'red'}">${ai.trend_miesiac_do_miesiaca || 'neutralny'}</span>
    </p>
  </div>
</div>

<div class="container">

  ${ai.alert_krytyczny ? `
  <div class="alert-box">
    <h4>⚠️ Alert Krytyczny</h4>
    <p>${ai.alert_krytyczny}</p>
  </div>` : ''}

  <div class="summary-box">
    <h3>📋 Podsumowanie Wykonawcze</h3>
    <p>${ai.podsumowanie_wykonawcze || 'Brak podsumowania AI'}</p>
  </div>

  <!-- ══════════════════════════════════════════
       GLOBALNE KPI
  ══════════════════════════════════════════ -->
  <div class="section">
    <h2>🎯 Kluczowe Wskaźniki — Wszystkie Kanały</h2>
    <div class="kpi-grid">
      <div class="kpi-card accent">
        <div class="label">Łączne Wydatki Rekl.</div>
        <div class="value">${pln(sum.totalAdSpend)}</div>
        <div class="sub">Google ${sum.googleAdsSpendPct}% | Meta ${sum.metaAdsSpendPct}%</div>
      </div>
      <div class="kpi-card green">
        <div class="label">Blended ROAS</div>
        <div class="value">${sum.blendedROAS}x</div>
        <div class="sub">Łączny zwrot z wydatków</div>
      </div>
      <div class="kpi-card">
        <div class="label">Łączne Konwersje</div>
        <div class="value">${num(sum.totalConversions)}</div>
        <div class="sub">Wartość: ${pln(sum.totalConversionValue)}</div>
      </div>
      <div class="kpi-card accent">
        <div class="label">Sesje GA4</div>
        <div class="value">${num(ga.totalSessions)}</div>
        <div class="sub">Użytkownicy: ${num(ga.totalUsers)}</div>
      </div>
      <div class="kpi-card meta">
        <div class="label">Meta Zasięg</div>
        <div class="value">${num(metaKpi.totalReach || meta.totalReach)}</div>
        <div class="sub">Wyd.: ${num(metaKpi.totalImpressions || meta.totalImpressions)}</div>
      </div>
      <div class="kpi-card">
        <div class="label">Social Organic Zasięg</div>
        <div class="value">${num(social.totalReach)}</div>
        <div class="sub">Eng.: ${num(social.totalEngagements)}</div>
      </div>
    </div>

    <h3>📊 Podział Budżetu Reklamowego</h3>
    <div style="margin-bottom:8px;display:flex;justify-content:space-between;font-size:13px">
      <span>🔵 Google Ads — <strong>${pln(ads.totalCostPLN)}</strong> (${sum.googleAdsSpendPct}%)</span>
      <span>🔷 Meta Ads — <strong>${pln(metaKpi.totalSpend || meta.totalSpend)}</strong> (${sum.metaAdsSpendPct}%)</span>
    </div>
    <div class="budget-bar-wrap">
      <div class="budget-bar-g" style="width:${googlePct}%">Google ${sum.googleAdsSpendPct}%</div>
      <div class="budget-bar-m" style="width:${metaPct}%">Meta ${sum.metaAdsSpendPct}%</div>
    </div>
  </div>

  <!-- ══════════════════════════════════════════
       GOOGLE ANALYTICS 4
  ══════════════════════════════════════════ -->
  <div class="section">
    <h2>📈 Google Analytics 4</h2>
    <div class="kpi-grid" style="margin-bottom:24px">
      <div class="kpi-card">
        <div class="label">Nowi Użytkownicy</div>
        <div class="value">${num(ga.totalNewUsers)}</div>
        <div class="sub">${num(ga.returningUsers)} powracających</div>
      </div>
      <div class="kpi-card">
        <div class="label">Bounce Rate</div>
        <div class="value">${pct(ga.avgBounceRate)}</div>
        <div class="sub">Śr. czas: ${ga.avgSessionDurationStr || 'N/A'}</div>
      </div>
      <div class="kpi-card">
        <div class="label">Odsłony</div>
        <div class="value">${num(ga.totalPageViews)}</div>
        <div class="sub">${ga.pagesPerSession} str./sesję</div>
      </div>
      <div class="kpi-card green">
        <div class="label">Wsp. Konwersji</div>
        <div class="value">${pct(ga.conversionRate)}</div>
        <div class="sub">${num(ga.totalConversions)} konwersji</div>
      </div>
    </div>
    <h3>Top Źródła Ruchu</h3>
    <table>
      <thead><tr><th>Źródło</th><th>Sesje</th><th>Udział %</th></tr></thead>
      <tbody>
        ${(ga.topSources || []).map(s => `
          <tr>
            <td>${s.source}</td>
            <td>${num(s.sessions)}</td>
            <td>${ga.totalSessions > 0 ? ((s.sessions / ga.totalSessions) * 100).toFixed(1) : 0}%</td>
          </tr>
        `).join('')}
      </tbody>
    </table>
  </div>

  <!-- ══════════════════════════════════════════
       GOOGLE ADS
  ══════════════════════════════════════════ -->
  <div class="section">
    <h2>💰 Google Ads</h2>
    <div class="kpi-grid" style="margin-bottom:24px">
      <div class="kpi-card accent">
        <div class="label">ROAS</div>
        <div class="value">${ads.ROAS}x</div>
        <div class="sub">Zwrot z wydatków</div>
      </div>
      <div class="kpi-card">
        <div class="label">Kliknięcia</div>
        <div class="value">${num(ads.totalClicks)}</div>
        <div class="sub">${num(ads.totalImpressions)} wyświetleń</div>
      </div>
      <div class="kpi-card">
        <div class="label">CTR</div>
        <div class="value">${pct(ads.avgCTR)}</div>
        <div class="sub">CPC: ${ads.avgCPC} PLN</div>
      </div>
      <div class="kpi-card green">
        <div class="label">CPA</div>
        <div class="value">${ads.CPA} PLN</div>
        <div class="sub">${num(ads.totalConversions)} konwersji</div>
      </div>
    </div>
    <h3>Top Kampanie Google Ads</h3>
    <table>
      <thead><tr><th>Kampania</th><th>Wyświetlenia</th><th>Kliknięcia</th><th>CTR</th><th>CPC</th><th>Wydatki</th></tr></thead>
      <tbody>${googleCampaignRows(ads.topCampaigns)}</tbody>
    </table>
  </div>

  <!-- ══════════════════════════════════════════
       META ADS — PEŁNA SEKCJA
  ══════════════════════════════════════════ -->
  <div class="section">
    <h2>📘 Meta Ads — Facebook &amp; Instagram</h2>

    <!-- INSIGHT PILLS -->
    <div class="insight-row">
      <div class="insight-pill blue">🏆 Top kampania (ROAS): <strong>&nbsp;${metaIns.topCampaignByROAS?.name || meta.topCampaignByROAS?.name || sum.meta?.topCampaign || 'N/A'}</strong></div>
      <div class="insight-pill green">📱 Najlepsza platforma: <strong>&nbsp;${metaPlat.bestPlatformByROAS || sum.meta?.topPlatform || 'N/A'}</strong></div>
      <div class="insight-pill purple">👥 Top segment: <strong>&nbsp;${metaDemo.topSegmentByConversions?.segment || sum.meta?.topSegment || 'N/A'}</strong></div>
      <div class="insight-pill orange">📊 Śr. częstotliwość: <strong>&nbsp;${metaIns.avgFrequency || metaKpi.avgFrequency || 'N/A'}x</strong></div>
      <div class="insight-pill blue">🖥️ Najlepsze urządzenie: <strong>&nbsp;${metaPlat.bestDeviceByConv || sum.meta?.bestDeviceByConv || 'N/A'}</strong></div>
      <div class="insight-pill green">🎂 Top wiek (konw.): <strong>&nbsp;${metaDemo.topAgeByConversions || sum.meta?.topAgeGroup || 'N/A'}</strong></div>
      <div class="insight-pill purple">⚥ Dom. płeć: <strong>&nbsp;${metaDemo.dominantGender || sum.meta?.topGender || 'N/A'}</strong></div>
    </div>

    <!-- KPI META GŁÓWNE -->
    <div class="kpi-grid" style="margin-bottom:28px">
      <div class="kpi-card meta">
        <div class="label">Wydatki Meta</div>
        <div class="value">${pln(metaKpi.totalSpend || meta.totalSpend)}</div>
        <div class="sub">${metaKpi.activeCampaigns || metaIns.activeCampaignsCount || 0} aktywnych kampanii</div>
      </div>
      <div class="kpi-card meta">
        <div class="label">ROAS</div>
        <div class="value">${metaKpi.overallROAS || meta.overallROAS}x</div>
        <div class="sub">Wartość zakupów: ${pln(metaKpi.totalPurchaseValue || meta.totalPurchaseValue)}</div>
      </div>
      <div class="kpi-card">
        <div class="label">Zasięg</div>
        <div class="value">${num(metaKpi.totalReach || meta.totalReach)}</div>
        <div class="sub">Częstotliwość: ${metaKpi.avgFrequency || meta.avgFrequency}x</div>
      </div>
      <div class="kpi-card">
        <div class="label">Wyświetlenia</div>
        <div class="value">${num(metaKpi.totalImpressions || meta.totalImpressions)}</div>
        <div class="sub">CPM: ${metaKpi.overallCPM || meta.overallCPM} PLN</div>
      </div>
      <div class="kpi-card">
        <div class="label">Kliknięcia</div>
        <div class="value">${num(metaKpi.totalClicks || meta.totalClicks)}</div>
        <div class="sub">CTR: ${metaKpi.overallCTR || meta.overallCTR}% | CPC: ${metaKpi.overallCPC || meta.overallCPC} PLN</div>
      </div>
      <div class="kpi-card green">
        <div class="label">Zakupy</div>
        <div class="value">${num(metaKpi.totalPurchases || meta.totalPurchases)}</div>
        <div class="sub">CPA: ${metaKpi.overallCPA || meta.overallCPA} PLN</div>
      </div>
      <div class="kpi-card">
        <div class="label">Leady</div>
        <div class="value">${num(metaKpi.totalLeads || meta.totalLeads)}</div>
        <div class="sub">Łącz. konwersje: ${num(metaKpi.totalConversions || meta.totalConversions)}</div>
      </div>
      <div class="kpi-card orange">
        <div class="label">Dodania do Koszyka</div>
        <div class="value">${num(metaKpi.totalAddToCart || meta.totalAddToCart)}</div>
        <div class="sub">Inicj. zakupu: ${num(metaKpi.totalInitCheckout || meta.totalInitCheckout)}</div>
      </div>
    </div>

    <!-- LEJEK SPRZEDAŻOWY -->
    <h3>🔽 Lejek Sprzedażowy Meta</h3>
    <div class="subsection">
      ${funnelBar('👥 Zasięg (Reach)',            metaKpi.totalReach        || meta.totalReach        || 0, funnelMax, '#1877f2')}
      ${funnelBar('👁️ Wyświetlenia (Impressions)', metaKpi.totalImpressions  || meta.totalImpressions  || 0, funnelMax, '#42a5f5')}
      ${funnelBar('🖱️ Kliknięcia (Clicks)',         metaKpi.totalClicks       || meta.totalClicks       || 0, funnelMax, '#0ea5e9')}
      ${funnelBar('📄 Odsłony Landing Page',        metaKpi.totalLandingViews || meta.totalLandingViews || 0, funnelMax, '#06b6d4')}
      ${funnelBar('🛒 Dodania do Koszyka',           metaKpi.totalAddToCart    || meta.totalAddToCart    || 0, funnelMax, '#f59e0b')}
      ${funnelBar('💳 Rozpoczęcie Zakupu',           metaKpi.totalInitCheckout || meta.totalInitCheckout || 0, funnelMax, '#f97316')}
      ${funnelBar('✅ Zakupy (Purchases)',            metaKpi.totalPurchases    || meta.totalPurchases    || 0, funnelMax, '#22c55e')}
    </div>

    <!-- WSZYSTKIE KAMPANIE META -->
    <h3>🏆 Wszystkie Kampanie Meta Ads</h3>
    <div class="table-scroll">
      <table>
        <thead>
          <tr>
            <th>Kampania</th>
            <th>Cel</th>
            <th>Status</th>
            <th>Wyświetlenia</th>
            <th>Kliknięcia</th>
            <th>CTR</th>
            <th>CPC</th>
            <th>ROAS</th>
            <th>Wydatki</th>
          </tr>
        </thead>
        <tbody>${metaCampaignRows(metaCamps)}</tbody>
      </table>
    </div>

    <!-- RANKINGI KAMPANII -->
    <div class="three-col" style="margin-top:20px">
      <div class="subsection">
        <h3 style="margin-top:0">💸 Top wg Wydatków</h3>
        <table>
          <thead><tr><th>Kampania</th><th>Wydatki</th></tr></thead>
          <tbody>
            ${(meta.topBySpendList || []).slice(0,3).map(c => `
              <tr><td>${c.name}</td><td>${pln(c.spend)}</td></tr>
            `).join('') || '<tr><td colspan="2">Brak</td></tr>'}
          </tbody>
        </table>
      </div>
      <div class="subsection">
        <h3 style="margin-top:0">📈 Top wg ROAS</h3>
        <table>
          <thead><tr><th>Kampania</th><th>ROAS</th></tr></thead>
          <tbody>
            ${(meta.topByROASList || []).slice(0,3).map(c => `
              <tr><td>${c.name}</td><td>${c.roas}x</td></tr>
            `).join('') || '<tr><td colspan="2">Brak</td></tr>'}
          </tbody>
        </table>
      </div>
      <div class="subsection">
        <h3 style="margin-top:0">🎯 Top wg Konwersji</h3>
        <table>
          <thead><tr><th>Kampania</th><th>Konwersje</th></tr></thead>
          <tbody>
            ${(meta.topByConvList || []).slice(0,3).map(c => `
              <tr><td>${c.name}</td><td>${num(c.conversions)}</td></tr>
            `).join('') || '<tr><td colspan="2">Brak</td></tr>'}
          </tbody>
        </table>
      </div>
    </div>

    <!-- PODZIAŁ NA PLATFORMY -->
    <h3>📊 Wyniki wg Platformy</h3>
    <div class="table-scroll">
      <table>
        <thead>
          <tr>
            <th>Platforma</th>
            <th>Wyświetlenia</th>
            <th>Kliknięcia</th>
            <th>Zasięg</th>
            <th>CTR</th>
            <th>CPM</th>
            <th>CPC</th>
            <th>Zakupy</th>
            <th>Udział Budżetu</th>
          </tr>
        </thead>
        <tbody>${platformRows(platBy)}</tbody>
      </table>
    </div>

    <!-- PODZIAŁ NA URZĄDZENIA -->
    <h3>📱 Wyniki wg Urządzenia</h3>
    <div class="table-scroll">
      <table>
        <thead>
          <tr>
            <th>Urządzenie</th>
            <th>Wyświetlenia</th>
            <th>Kliknięcia</th>
            <th>Zasięg</th>
            <th>CTR</th>
            <th>Zakupy</th>
            <th>Udział Budżetu</th>
          </tr>
        </thead>
        <tbody>${deviceRows(devBy)}</tbody>
      </table>
    </div>

    <!-- KOMBINACJE PLATFORMA × URZĄDZENIE -->
    <h3>🔀 Kombinacje Platforma × Urządzenie</h3>
    <div class="table-scroll">
      <table>
        <thead>
          <tr>
            <th>Kombinacja</th>
            <th>Wyświetlenia</th>
            <th>Kliknięcia</th>
            <th>Zasięg</th>
            <th>CTR</th>
            <th>Zakupy</th>
            <th>Leady</th>
            <th>Udział Budżetu</th>
          </tr>
        </thead>
        <tbody>${combinedRows(combBy)}</tbody>
      </table>
    </div>

    <!-- DEMOGRAFIA -->
    <h3>👥 Demografa — Grupy Wiekowe</h3>
    <div class="table-scroll">
      <table>
        <thead>
          <tr>
            <th>Wiek</th>
            <th>Zasięg</th>
            <th>Kliknięcia</th>
            <th>CTR</th>
            <th>CPA</th>
            <th>Zakupy</th>
            <th>Leady</th>
            <th>Koszyk</th>
            <th>Udział Budżetu</th>
          </tr>
        </thead>
        <tbody>${ageRows(ageBy)}</tbody>
      </table>
    </div>

    <h3>⚥ Demografia — Płeć</h3>
    <div class="table-scroll">
      <table>
        <thead>
          <tr>
            <th>Płeć</th>
            <th>Zasięg</th>
            <th>Kliknięcia</th>
            <th>CTR</th>
            <th>CPA</th>
            <th>Zakupy</th>
            <th>Leady</th>
            <th>Koszyk</th>
            <th>Udział Budżetu</th>
          </tr>
        </thead>
        <tbody>${genderRows(genBy)}</tbody>
      </table>
    </div>

    <!-- TOP SEGMENTY WIEK × PŁEĆ -->
    <h3>🎯 Top Segmenty Wiek × Płeć</h3>
    <div class="table-scroll">
      <table>
        <thead>
          <tr>
            <th>Segment</th>
            <th>Zasięg</th>
            <th>Kliknięcia</th>
            <th>CTR</th>
            <th>CPA</th>
            <th>Zakupy</th>
            <th>Koszyk</th>
            <th>Udział Budżetu</th>
          </tr>
        </thead>
        <tbody>${segmentRows(topSegs.length > 0 ? topSegs : segments)}</tbody>
      </table>
    </div>

    <!-- PODSUMOWANIE DEMOGRAFICZNE -->
    <div class="three-col" style="margin-top:20px">
      <div class="subsection">
