}

// ── Pobierz wiersze ───────────────────────────
const rows = data?.data || [];

// ── Mapy agregacji ────────────────────────────
const ageMap     = {};
const genderMap  = {};
const segmentMap = {}; // wiek + płeć razem

// ── Liczniki globalne ─────────────────────────
let totalSpend       = 0;
let totalImpressions = 0;
let totalClicks      = 0;
let totalReach       = 0;
