let totalLeads       = 0;

// ── Kolejność grup wiekowych ──────────────────
const ageOrder = ['13-17','18-24','25-34','35-44','45-54','55-64','65+'];

// ── Pętla po wierszach ────────────────────────
for (const row of rows) {
  const age    = row.age    || 'unknown';
