// ============================================
// WALIDACJA DANYCH Z FORMULARZA
// ============================================

const body = $json.body || $json;

// Wymagane pola
const required = ['company', 'apiKey', 'apiSecret', 'email'];
const missing = required.filter(f => !body[f] || body[f].toString().trim() === '');

if (missing.length > 0) {
  throw new Error(`Brakujące pola: ${missing.join(', ')}`);
}

// Walidacja email
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(body.email)) {
  throw new Error(`Nieprawidłowy email: ${body.email}`);
}

return [{
  json: {
    company:    body.company.trim(),
    apiKey:     body.apiKey.trim(),
    apiSecret:  body.apiSecret.trim(),
    email:      body.email.trim(),
    phone:      body.phone?.trim() || '',
    plan:       body.plan?.trim() || 'basic',
    notes:      body.notes?.trim() || '',
    createdAt:  new Date().toISOString()
  }
}];

// ============================================
// GENERUJ NOWE ID I PRZYGOTUJ KLIENTA
// ============================================

// Dane z poprzedniego kroku (walidacja)
const newClientData = $('✅ Waliduj Dane').first().json;

// Obecna lista klientów
let existingData;
try {
  existingData = $json;
} catch(e) {
  existingData = { clients: [], lastId: 0 };
}

// Bezpieczne parsowanie
const clients = Array.isArray(existingData.clients) 
  ? existingData.clients 
  : [];

// ============================================
// GENEROWANIE NOWEGO ID
// ============================================

// Metoda 1: lastId + 1 (szybka)
const lastId = existingData.lastId || 0;
const newId = lastId + 1;

// Metoda 2 (backup): znajdź max z tablicy
// const maxId = clients.length > 0 
//   ? Math.max(...clients.map(c => c.id || 0)) 
//   : 0;
// const newId = maxId + 1;

// Formatowanie ID: C-0001, C-0002...
const formattedId = `C-${String(newId).padStart(4, '0')}`;

// ============================================
// NOWY OBIEKT KLIENTA
// ============================================

const newClient = {
  id:         newId,
  clientId:   formattedId,      // czytelny identyfikator
  company:    newClientData.company,
  email:      newClientData.email,
  phone:      newClientData.phone,
  plan:       newClientData.plan,
  apiKey:     newClientData.apiKey,
  apiSecret:  newClientData.apiSecret,
  notes:      newClientData.notes,
  createdAt:  newClientData.createdAt,
  updatedAt:  newClientData.createdAt,
  active:     true
};

// ============================================
// ZAKTUALIZOWANA LISTA
// ============================================

const updatedData = {
  lastId:    newId,                        // zapamiętaj ostatnie ID
  updatedAt: new Date().toISOString(),
  total:     clients.length + 1,
  clients:   [...clients, newClient]       // dodaj nowego klienta
};

console.log(`✅ Dodano klienta: ${formattedId} — ${newClientData.company}`);

return [{
  json: {
    newClient,
    updatedData,
    newId,
    formattedId
  }
}];

// ============================================
// WYŚLIJ ODPOWIEDŹ DO FORMULARZA
// ============================================

const data = $('🆔 Generuj ID i Buduj JSON').first().json;

return [{
  json: {
    success:   true,
    message:   `Klient ${data.formattedId} został pomyślnie dodany!`,
    clientId:  data.formattedId,
    company:   data.newClient.company,
    createdAt: data.newClient.createdAt
  }
}];

// ============================================
// PRZYGOTUJ DATY DLA POPRZEDNIEGO MIESIĄCA
// ============================================

const now = new Date();

const prevMonthStart = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const prevMonthEnd   = new Date(now.getFullYear(), now.getMonth(), 0);

function formatDate(d) {
  return d.toISOString().split('T')[0];
}
function formatDatePL(d) {
  return d.toLocaleDateString('pl-PL', { year: 'numeric', month: 'long' });
}

const startDate  = formatDate(prevMonthStart);
const endDate    = formatDate(prevMonthEnd);
const startTs    = prevMonthStart.getTime();
const endTs      = prevMonthEnd.getTime();
const monthLabel = formatDatePL(prevMonthStart);
const monthShort = prevMonthStart.toLocaleDateString('pl-PL', { month: '2-digit', year: 'numeric' });

// Daty dla porównania (miesiąc wcześniej)
const prevPrevStart = new Date(now.getFullYear(), now.getMonth() - 2, 1);
const prevPrevEnd   = new Date(now.getFullYear(), now.getMonth() - 1, 0);

console.log(`Generuję raport za: ${monthLabel} (${startDate} → ${endDate})`);

return [{
  json: {
    startDate,
    endDate,
    startTs,
    endTs,
    monthLabel,
    monthShort,
    reportTitle:   `Raport Miesięczny — ${monthLabel}`,
    generatedAt:   now.toISOString(),
    generatedAtPL: now.toLocaleDateString('pl-PL', {
      day: '2-digit', month: 'long', year: 'numeric',
