// ============================================
// META ADS — PRZETWÓRZ ODPOWIEDŹ
// ============================================

const raw = $json;
const dates = $('📆 Przygotuj Daty').first().json;

// Obsługa błędów API
if (raw.error) {
  console.error(`❌ Meta Ads błąd: ${raw.error.message}`);
  return [{
    json: {
      source:     'meta_ads',
      success:    false,
      error:      raw.error.message,
      data:       [],
      summary:    {},
      monthLabel: dates.monthLabel
    }
  }];
}

const campaigns = raw.data || [];

// Sumuj dane ze wszystkich kampanii
const summary = campaigns.reduce((acc, camp) => {
  acc.totalSpend      += parseFloat(camp.spend || 0);
  acc.totalImpressions += parseInt(camp.impressions || 0);
  acc.totalClicks      += parseInt(camp.clicks || 0);
  acc.totalReach       += parseInt(camp.reach || 0);
  return acc;
}, {
  totalSpend:       0,
  totalImpressions: 0,
  totalClicks:      0,
  totalReach:       0
});

// Oblicz CTR i CPC
summary.avgCTR = summary.totalImpressions > 0
  ? ((summary.totalClicks / summary.totalImpressions) * 100).toFixed(2)
  : 0;

summary.avgCPC = summary.totalClicks > 0
  ? (summary.totalSpend / summary.totalClicks).toFixed(2)
  : 0;

console.log(`✅ Meta Ads: ${campaigns.length} kampanii, wydano ${summary.totalSpend} PLN`);

return [{
  json: {
    source:     'meta_ads',
    success:    true,
    monthLabel: dates.monthLabel,
    startDate:  dates.startDate,
    endDate:    dates.endDate,
    campaigns,
    summary
  }
}];

// ============================================
// GOOGLE ADS — PRZYGOTUJ ZAPYTANIE
// ============================================

const dates = $('📆 Przygotuj Daty').first().json;

const CUSTOMER_ID    = 'TWOJE_CUSTOMER_ID';      // bez myślników np. 1234567890
const DEVELOPER_TOKEN = 'TWOJ_DEVELOPER_TOKEN';
const MANAGER_ID     = 'TWOJ_MANAGER_ID';        // jeśli używasz MCC

// Google Ads Query Language (GAQL)
const query = `
  SELECT
    campaign.name,
    campaign.status,
    metrics.impressions,
    metrics.clicks,
    metrics.cost_micros,
    metrics.ctr,
    metrics.average_cpc,
    metrics.conversions,
    metrics.cost_per_conversion
  FROM campaign
  WHERE segments.date BETWEEN '${dates.startDate}' AND '${dates.endDate}'
    AND campaign.status = 'ENABLED'
  ORDER BY metrics.cost_micros DESC
`.trim();

const url = `https://googleads.googleapis.com/v16/customers/${CUSTOMER_ID}/googleAds:searchStream`;

console.log(`🟡 Google Ads — przygotowano zapytanie GAQL`);
console.log(`   Okres: ${dates.startDate} → ${dates.endDate}`);

return [{
  json: {
    source:        'google_ads',
    url,
    query,
    customerId:    CUSTOMER_ID,
    developerToken: DEVELOPER_TOKEN,
    managerId:     MANAGER_ID,
    startDate:     dates.startDate,
    endDate:       dates.endDate,
    monthLabel:    dates.monthLabel
  }
}];

// ============================================
// GOOGLE ADS — PRZETWÓRZ ODPOWIEDŹ
// ============================================

const raw = $json;
const dates = $('📆 Przygotuj Daty').first().json;

if (raw.error || !raw[0]?.results) {
  console.error('❌ Google Ads błąd lub brak danych');
  return [{
    json: {
      source:     'google_ads',
      success:    false,
      error:      raw.error?.message || 'Brak wyników',
      data:       [],
      summary:    {},
      monthLabel: dates.monthLabel
    }
  }];
}

const results = raw[0].results || [];

// Konwersja micros → PLN (1 PLN = 1,000,000 micros)
const campaigns = results.map(r => ({
  name:          r.campaign?.name || '',
  status:        r.campaign?.status || '',
  impressions:   parseInt(r.metrics?.impressions || 0),
  clicks:        parseInt(r.metrics?.clicks || 0),
  spend:         (parseInt(r.metrics?.cost_micros || 0) / 1_000_000).toFixed(2),
  ctr:           parseFloat(r.metrics?.ctr || 0).toFixed(4),
  avgCpc:        (parseInt(r.metrics?.average_cpc || 0) / 1_000_000).toFixed(2),
  conversions:   parseFloat(r.metrics?.conversions || 0),
  costPerConv:   (parseInt(r.metrics?.cost_per_conversion || 0) / 1_000_000).toFixed(2)
}));

const summary = campaigns.reduce((acc, c) => {
  acc.totalSpend       += parseFloat(c.spend);
  acc.totalImpressions += c.impressions;
  acc.totalClicks      += c.clicks;
  acc.totalConversions += c.conversions;
  return acc;
}, {
  totalSpend: 0, totalImpressions: 0,
  totalClicks: 0, totalConversions: 0
});

console.log(`✅ Google Ads: ${campaigns.length} kampanii, wydano ${summary.totalSpend.toFixed(2)} PLN`);

return [{
  json: {
    source:     'google_ads',
    success:    true,
    monthLabel: dates.monthLabel,
    startDate:  dates.startDate,
    endDate:    dates.endDate,
    campaigns,
    summary
  }
}];

