const dates = $('📆 Przygotuj Daty').first().json;

const ITOP_URL      = 'https://TWOJ-ITOP.pl';
const ITOP_USER     = 'TWOJ_LOGIN';
const ITOP_PASSWORD = 'TWOJE_HASLO';
const ITOP_VERSION  = '1.3';

// iTop REST API — pobierz zgłoszenia z okresu
const jsonData = JSON.stringify({
  operation:     'core/get',
  class:         'UserRequest',
  key:           `SELECT UserRequest WHERE start_date >= '${dates.startDate}' AND start_date <= '${dates.endDate}'`,
  output_fields: 'id,ref,title,status,priority,agent_id_friendlyname,org_id_friendlyname,start_date,close_date,time_to_resolve'
});

const url = `${ITOP_URL}/webservices/rest.php`
  + `?version=${ITOP_VERSION}`
  + `&json_data=${encodeURIComponent(jsonData)}`
  + `&login_mode=basic`;

console.log(`🔵 iTop — przygotowano zapytanie`);
console.log(`   Szukam zgłoszeń: ${dates.startDate} → ${dates.endDate}`);

return [{
  json: {
    source:     'itop',
    url,
    user:       ITOP_USER,
    password:   ITOP_PASSWORD,
    startDate:  dates.startDate,
    endDate:    dates.endDate,
    monthLabel: dates.monthLabel
  }
}];

// ============================================
// ITOP — PRZETWÓRZ ODPOWIEDŹ
// ============================================

const raw = $json;
const dates = $('📆 Przygotuj Daty').first().json;

if (raw.code !== 0) {
  console.error(`❌ iTop błąd: ${raw.message}`);
  return [{
    json: {
      source:     'itop',
      success:    false,
      error:      raw.message || 'Błąd API',
      data:       [],
      summary:    {},
      monthLabel: dates.monthLabel
    }
  }];
}

// Pobierz listę zgłoszeń
const objects = raw.objects || {};
const tickets = Object.values(objects).map(obj => obj.fields || obj);

// Statystyki zgłoszeń
const statusCount = tickets.reduce((acc, t) => {
  const st = t.status || 'unknown';
  acc[st] = (acc[st] || 0) + 1;
  return acc;
}, {});

const priorityCount = tickets.reduce((acc, t) => {
  const pr = t.priority || 'unknown';
  acc[pr] = (acc[pr] || 0) + 1;
  return acc;
}, {});

// Oblicz średni czas rozwiązania
const resolved = tickets.filter(t => t.close_date && t.start_date);
const avgResolutionHours = resolved.length > 0
  ? resolved.reduce((sum, t) => {
      const diff = new Date(t.close_date) - new Date(t.start_date);
      return sum + (diff / 3_600_000); // ms → godziny
    }, 0) / resolved.length
  : 0;

const summary = {
  totalTickets:       tickets.length,
  resolved:           statusCount['resolved']  || 0,
  closed:             statusCount['closed']    || 0,
  open:               statusCount['new']       || 0,
  inProgress:         statusCount['assigned']  || 0,
  highPriority:       priorityCount['1_high']  || 0,
  mediumPriority:     priorityCount['2_medium']|| 0,
  lowPriority:        priorityCount['3_low']   || 0,
  avgResolutionHours: avgResolutionHours.toFixed(1),
  statusBreakdown:    statusCount,
  priorityBreakdown:  priorityCount
};

console.log(`✅ iTop: ${tickets.length} zgłoszeń, ${summary.resolved} rozwiązanych`);

return [{
  json: {
    source:     'itop',
    success:    true,
    monthLabel: dates.monthLabel,
    startDate:  dates.startDate,
    endDate:    dates.endDate,
    tickets,
    summary
  }
}];
